import{_ as l,C as s,o as d,c as p,a1 as n,j as e,E as r,w as o,a as i}from"./chunks/framework.BX4nIuL2.js";const x=JSON.parse('{"title":"SLA background","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/5.SLAbackground.md","filePath":"courses/fab-course/doc/3_3dprinter/5.SLAbackground.md"}'),h={name:"courses/fab-course/doc/3_3dprinter/5.SLAbackground.md"},m={href:"https://theorthocosmos.com/laser-sla-vs-dlp-vs-masked-SLA-3D-printing-technology-compared/",target:"_blank",rel:"noreferrer"},u={href:"https://formlabs.com/blog/3d-printing-technology-comparison-sla-dlp/",target:"_blank",rel:"noreferrer"},c={href:"https://formlabs.com/blog/3d-printing-technology-comparison-sla-dlp/",target:"_blank",rel:"noreferrer"},g={href:"https://formlabs.com/blog/3d-printing-technology-comparison-sla-dlp/",target:"_blank",rel:"noreferrer"};function f(b,t,y,w,v,S){const a=s("center");return d(),p("div",null,[t[15]||(t[15]=n('<h1 id="sla-background" tabindex="-1">SLA background <a class="header-anchor" href="#sla-background" aria-label="Permalink to &quot;SLA background&quot;">​</a></h1><h2 id="_1-define-of-sla" tabindex="-1">1. Define of SLA <a class="header-anchor" href="#_1-define-of-sla" aria-label="Permalink to &quot;1. Define of SLA&quot;">​</a></h2><p>Stereolithography (SLA) is the first method in the history of 3D printing which was invented by <a href="https://en.wikipedia.org/wiki/Chuck_Hull" target="_blank" rel="noreferrer">Chuck Hull( co-founder of 3D Systems)</a>. In 1992, 3D Systems produced the first SLA machine. <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-220500@2x.png" alt=""></p><h2 id="_2-types-of-sla" tabindex="-1">2. Types of SLA <a class="header-anchor" href="#_2-types-of-sla" aria-label="Permalink to &quot;2. Types of SLA&quot;">​</a></h2><p>There are three main types of SLA: <strong>laser-based stereolithography (laser SLA)</strong>, <strong>digital light processing stereolithography (DLP-SLA)</strong>, and <strong>masked SLA (MSLA)</strong>. For all these SLA, a tank of liquid resin is selectively exposed to light in order to form very thin solid layers that stack up to create one solid object.</p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/DigitalWorkflow.001.jpeg" alt=""></p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/MSLA.001.jpeg" alt=""></p>',7)),e("p",null,[e("a",m,[r(a,null,{default:o(()=>[...t[0]||(t[0]=[i("reference from the ortho cosmos",-1)])]),_:1})])]),e("ul",null,[e("li",null,[t[9]||(t[9]=e("p",null,"Laser SLA involved a UV laser solidifying photopolymer resin, a liquid with viscosity. This is the most popular in the world and we would introduce SLA according to laser SLA",-1)),e("ul",null,[t[4]||(t[4]=e("li",null,"Designer design 3D CAD model and generate the STL file;Translate to 3D printer's machine code that contains the information for each layer;",-1)),t[5]||(t[5]=e("li",null,"The build platform could move up and down in the tank of liquid resin. For the first layer, the distance from build platform to the surface of liquid is about one layer height;",-1)),t[6]||(t[6]=e("li",null,"Then a UV Laser irradiate across the print area of liquid resin( draw each layer of the object by two deflection mirrors driven by a motor, known as galvanometers (one on the X axis and one on the Y axis)) , solidifying resin as it moves along;",-1)),t[7]||(t[7]=e("li",null,"When a layer is finished, the platform moves one layer height and the sweeper blade re-coats the surface;",-1)),t[8]||(t[8]=e("li",null,"The process then repeats until the part is complete;",-1)),e("li",null,[t[2]||(t[2]=i("Once all layers are printed, the object needs to be rinsed with a solvent and placed in an ultraviolet oven to finish the process to get high mechanical and thermal properties. ",-1)),t[3]||(t[3]=e("img",{src:"https://github.com/bobwu0214/dm360.github.io/raw/master/Img/slaprincipl.jpg",alt:""},null,-1)),e("a",u,[r(a,null,{default:o(()=>[...t[1]||(t[1]=[i("reference from formlabs",-1)])]),_:1})])])])]),t[10]||(t[10]=e("li",null,[e("p",null,[i("DLP, similar with Laser SLA, they use light to solid layers that stack up to create one solid object. The difference is the light source. DLP use "),e("strong",null,"digital projector screen"),i(" to flash an image across the resin tank at once, Thus all points of a layer can be cured simultaneously. So it would faster than laser SLA. In the meantime ,DLP has some limitation compare with SLA;")]),e("ul",null,[e("li",null,"The DLP model similar with wax, the mechanical and thermal properties is low, so it can't be a true prototype in industry. But it can be a part of Lost-Wax process for jeweler;"),e("li",null,"The digital light projector has limited in resolutions. The model has minimum pixel size and surface quality is not good as SLA."),e("li",null,"If we want get bigger model in some surface quality, we have to need high-definition projector but it lead to high cost;")])],-1))]),e("p",null,[t[13]||(t[13]=e("img",{src:"https://github.com/bobwu0214/dm360.github.io/raw/master/Img/dlp2.png",alt:""},null,-1)),e("a",c,[r(a,null,{default:o(()=>[...t[11]||(t[11]=[i("reference from formlabs",-1)])]),_:1})]),t[14]||(t[14]=e("img",{src:"https://github.com/bobwu0214/dm360.github.io/raw/master/Img/slavsdpl.png",alt:""},null,-1)),e("a",g,[r(a,null,{default:o(()=>[...t[12]||(t[12]=[i("reference from formlabs",-1)])]),_:1})])]),t[16]||(t[16]=n('<ul><li>MSLA&#39;s light source is LED array, the light would irradiate across LCD panel(LCD panel is digital display and composed of square pixel, and the size of pixel would determine the precision of MSLA parts) ,then go to resin tank.Thus all points of a layer can be cured simultaneously. <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/MSLAprinciple.jpeg" alt=""></li></ul><h2 id="_3-customer-and-industry-sla-3d-printer" tabindex="-1">3. Customer and Industry SLA 3D printer <a class="header-anchor" href="#_3-customer-and-industry-sla-3d-printer" aria-label="Permalink to &quot;3. Customer and Industry SLA 3D printer&quot;">​</a></h2><p>There are two kinds of SLA machines depend on usage: Customer 3D printers include DLP, MSLA, and some desktop laser SLA. Most machines are desktop and designer can direct print model after design. Maker, designer and DIY would use them to make prototype, gift.</p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/customer3d.jpg" alt=""></p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/slatype.jpg" alt=""></p><p>But industry SLA 3D printer would be more professional. It used in prototype test ,product. The following tab is the compare.</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">Customer SLA</th><th style="text-align:left;">Industry SLA</th></tr></thead><tbody><tr><td style="text-align:left;">Advantage</td><td style="text-align:left;"><div>Lower cost</div><div>Widely available</div></td><td style="text-align:left;"><div>Very large build size</div><div>Faster build times</div></td></tr><tr><td style="text-align:left;">Disadvantage</td><td style="text-align:left;"><div>Small build size</div><div>Smaller material range</div><div>Requires more post-processing</div></td><td style="text-align:left;"><div>Higher cost</div><div>Require specialist operator</div><div>Changing material involves emptying the whole tank</div></td></tr><tr><td style="text-align:left;">Popular SLA printer manufacturers</td><td style="text-align:left;"><a href="https://formlabs.com" target="_blank" rel="noreferrer">formlabs</a></td><td style="text-align:left;"><a href="https://www.3dsystems.com/" target="_blank" rel="noreferrer">3D systems</a>,<a href="https://www.stratasys.com/" target="_blank" rel="noreferrer">stratasys</a>,<a href="http://en.union-tek.com/" target="_blank" rel="noreferrer">Union-tech</a>,<a href="http://www.zero-tek.com/en/index.html" target="_blank" rel="noreferrer">Zrapid</a></td></tr><tr><td style="text-align:left;">Build size</td><td style="text-align:left;">Up to 145 x 145 x 175 mm</td><td style="text-align:left;">Up to 1500 x 750 x 500 mm</td></tr><tr><td style="text-align:left;">Typical layer height</td><td style="text-align:left;">25 to 100 microns</td><td style="text-align:left;">25 to 150 microns</td></tr><tr><td style="text-align:left;">Dimensional Accuracy</td><td style="text-align:left;">± 0.5% (lower limit: ± 0.010 - 0.250 mm)</td><td style="text-align:left;">± 0.15% (lower limit ± 0.010 - 0.030 mm)</td></tr></tbody></table><h2 id="_4-benefits-and-limitations" tabindex="-1">4. Benefits and limitations <a class="header-anchor" href="#_4-benefits-and-limitations" aria-label="Permalink to &quot;4.  Benefits and limitations&quot;">​</a></h2><p>SLA is very popular in prototype market because of the following, in the meantime there are some limitation during application <strong>benefits</strong>:</p><ul><li>It can offer higher resolution printing than many another 3D printing technology. You can get parts with fine detail and surface finishes.</li><li>Similar with another 3D printing technology, SLA can easily make complex geometry which is impossible for traditional manufacturing. It is cool method for visual prototype;</li><li>There are many different specialty SLA materials available for us , such as standard, clear, flexible, high temperature resistant;</li><li>Normally, SLA 3D printer can finish 3D model in two days after confirm the data with vendor.</li></ul><p><strong>limitation</strong></p><ul><li>The mechanical performance is not enough for functional prototype and product;</li><li>The materials are limited compared with injection molding and CNC;</li><li>For many material, the SLA parts&#39; mechanical properties and color appearance would change minor after some months. It may influence the usage;</li><li>Most of SLA parts need support during SLA 3D printing, so it need post process and it will influence the surface and size. It need leave some space during design and manual experience in post process to reduce the influence.</li></ul><h2 id="_5-material" tabindex="-1">5. Material <a class="header-anchor" href="#_5-material" aria-label="Permalink to &quot;5. Material&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/slamaterial.png" alt=""></p><h2 id="_1-material" tabindex="-1">1 Material <a class="header-anchor" href="#_1-material" aria-label="Permalink to &quot;1 Material&quot;">​</a></h2><p>There are many different specialty SLA materials available for us , such as standard, clear, flexible, high temperature resistant;</p><table tabindex="0"><thead><tr><th>Material</th><th>Quotation (RMB/g)</th><th>Color</th><th>Precision (um)</th><th>Melting point (℃)</th><th>Hardness (D2240)</th><th>Density (g/cm³)</th></tr></thead><tbody><tr><td>Standard</td><td>1</td><td>milky</td><td>50-100</td><td>41</td><td>79D</td><td>1.14</td></tr><tr><td>Transparent</td><td>5</td><td><div>translucent</div><div>transparent</div></td><td>50-100</td><td>47</td><td>87D</td><td>1.12</td></tr><tr><td>Engine performance</td><td>12</td><td>milky</td><td>50-100</td><td>119</td><td>92D</td><td>1.14</td></tr><tr><td>Soft</td><td>6.5</td><td>light yellow</td><td>50-100</td><td>N/A</td><td>N/A</td><td>1.14</td></tr><tr><td>Durable</td><td>1.8</td><td>milky</td><td>50-100</td><td>49</td><td>82D</td><td>1.14</td></tr></tbody></table><p>The table below show the description of application</p><table tabindex="0"><thead><tr><th>Resin type</th><th>description</th><th>application</th></tr></thead><tbody><tr><td>Standard</td><td>Most popular used in daily industry and offer high detail surface finish(50 -100um)</td><td>Ideal for high detail prototypes and models which is just for appearance and assemble aim</td></tr><tr><td>Transparent</td><td>3D printer use transparent resin to make model and then need post process technology. It can offer designer model with transparent feeling, which lies between translucent and water-clear</td><td>Models requiring high clarity, Headlamps and lenses, Fluid flow and visualization models</td></tr><tr><td>Engine performance</td><td>Engine performance resin own engineering properties which produce strong, stiff, high-tempe resistant composite parts that are ideal for function test</td><td>Wind tunnel testing for aerodynamic design optimization, High-temperature testing,Electrical casings, Automotive housings, Tooling</td></tr><tr><td>Soft</td><td>SLA 3D printer can directly print soft flexible prototypes and models that are similar with silicon rubber. This ability (quickly to prototype silicon parts before mass manufacturing) is important to the development of finial products</td><td>wearable equipment, robot</td></tr><tr><td>Durable</td><td>This durable stereolithography material &#39;s look and feel is almost indistinguishable from finished traditional thermoplastics, making it perfect for functional testing applications – resulting in time, money and material savings during product development</td><td>aerospace, automotive, medical, consumer products and electronics</td></tr></tbody></table><h2 id="_6-application" tabindex="-1">6.Application <a class="header-anchor" href="#_6-application" aria-label="Permalink to &quot;6.Application&quot;">​</a></h2><h4 id="_6-1-rapid-prototyping" tabindex="-1">6.1. Rapid Prototyping <a class="header-anchor" href="#_6-1-rapid-prototyping" aria-label="Permalink to &quot;6.1. Rapid Prototyping&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-224500@2x.png" alt=""></p><p>if designers own customer SLA 3D printer, they can quickly print the physical object after design.</p><ul><li>Verify initial ideals with low-risk quickly;</li><li>After assembling functional prototype, designer can test the reliable and operation.</li><li>In this step we can choice material from rubber to rid, color from transparent to milky which is close to real production</li><li>Pre- production: Before mass production, SLA can used in two aspects: <ul><li>Direct make small batch：the cost in every may lower than injection molding or CNC;</li><li>We can use SLA to manufacture silicon rubber mold and it can use 20-100 times.So it can be used in small batch injection mold. Silicon rubber mold has advantage in cost and time comparing with steel mold.</li></ul></li></ul><h4 id="_6-2-production" tabindex="-1">6.2. Production <a class="header-anchor" href="#_6-2-production" aria-label="Permalink to &quot;6.2. Production&quot;">​</a></h4><p>SLA has big advantage in some details(for example:channel in object ,complex shape). If we use traditional method ,the mold would be very complex; even we need cut one object to some piece, then manufacture and assemble them together, the workload is very high;</p><ul><li>Tool for mass production: For some injection object, its shape is complex and has high requirement in cooling, so engineer would design conformal cooling channels in injection mold. It will save cost and improve the quality.</li></ul><h4 id="_6-3-rapid-mold" tabindex="-1">6.3. Rapid mold <a class="header-anchor" href="#_6-3-rapid-mold" aria-label="Permalink to &quot;6.3. Rapid mold&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-222439@2x.png" alt=""> Some engine performance resign would have high performance in strength and wearing resistance，in the meantime it can be manufacture fast(1 or 2days，but tranditation stainless stell mold need at least 1month).So it is cool to make low volume product between prototype and mass production.</p><h4 id="_6-4-customer-production" tabindex="-1">6.4. Customer production <a class="header-anchor" href="#_6-4-customer-production" aria-label="Permalink to &quot;6.4. Customer production&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-223541@2x.png" alt=""> Earphone&#39;s application in music especial for musician. Insole used for somebody have problem in foot,for example Diabetes foot， correct foot shape，etc</p><h4 id="_6-5-pdms-chip" tabindex="-1">6.5. PDMS chip <a class="header-anchor" href="#_6-5-pdms-chip" aria-label="Permalink to &quot;6.5. PDMS chip&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/1111.jpeg" alt=""></p><p>PDMS chip can used in medical，biology ，chemistry test It build small space for test system</p>',34))])}const A=l(h,[["render",f]]);export{x as __pageData,A as default};
